// Import all SVGs as React components
import { ReactComponent as ArrowPathIcon } from '../assets/icons/arrow-path.svg';
import { ReactComponent as ArrowTrendingUpIcon } from '../assets/icons/arrow-trending-up.svg';
import { ReactComponent as ChartPieIcon } from '../assets/icons/chart-pie.svg';
import { ReactComponent as ChevronDownIcon } from '../assets/icons/chevron-down.svg';
import { ReactComponent as ChevronLeftIcon } from '../assets/icons/chevron-left.svg';
import { ReactComponent as ChevronRightIcon } from '../assets/icons/chevron-right.svg';
import { ReactComponent as ChevronUpSolidIcon } from '../assets/icons/chevron-up-solid.svg';
import { ReactComponent as ChevronUpIcon } from '../assets/icons/chevron-up.svg';
import { ReactComponent as CogIcon } from '../assets/icons/cog-8-tooth.svg';
import { ReactComponent as CubeIcon } from '../assets/icons/cube-16-solid.svg';
import { ReactComponent as LinkSolidIcon } from '../assets/icons/link-solid.svg';
import { ReactComponent as LinkIcon } from '../assets/icons/link.svg';
import { ReactComponent as SearchIcon } from '../assets/icons/search.svg';
import { ReactComponent as XMarkIcon } from '../assets/icons/x-mark.svg';

export {
  ArrowPathIcon,
  ArrowTrendingUpIcon,
  ChartPieIcon,
  ChevronDownIcon,
  ChevronLeftIcon,
  ChevronRightIcon,
  ChevronUpSolidIcon,
  ChevronUpIcon,
  CogIcon,
  CubeIcon,
  LinkSolidIcon,
  LinkIcon,
  SearchIcon,
  XMarkIcon,
};
